<style id='mbn-theme-div-wrap-style-inline-css'>
/**
 * Div Wrap Block Styles
 */

.div-wrap-block {
  position: relative;
  width: 100%;
  overflow: hidden;
}

/* Video background container */
.div-wrap-video-background {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  overflow: hidden;
  z-index: 0;
}

/* Video element */
.div-wrap-video {
  position: absolute;
  top: 50%;
  left: 50%;
  min-width: 100%;
  min-height: 100%;
  width: auto;
  height: auto;
  transform: translate(-50%, -50%);
  object-fit: cover;
}

/* Content wrapper */
.div-wrap-content {
  position: relative;
  z-index: 1;
}

/* Ensure inner blocks don't have margin collapse issues */
.div-wrap-content > .block-editor-inner-blocks,
.div-wrap-content > .block-editor-block-list__layout {
  margin: 0;
}

/* Editor specific styles */
.wp-block-mbn-theme-div-wrap.div-wrap-block {
  min-height: 100px;
}

